import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response
import okhttp3.logging.HttpLoggingInterceptor
import java.util.concurrent.TimeUnit

class NetworkClient {

    private val client: OkHttpClient

    init {
        val logging = HttpLoggingInterceptor().apply {
            level = HttpLoggingInterceptor.Level.BODY
        }

        client = OkHttpClient.Builder()
            .addInterceptor(logging)
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()
    }

    fun getFromLocalDevice(ip: String): Response? {
        val url = "http://$ip"
        val request = Request.Builder()
            .url(url)
            .build()

        return client.newCall(request).execute()
    }

    fun getFromCloudApi(endpoint: String): Response? {
        val url = "https://api.example.com/$endpoint"
        val request = Request.Builder()
            .url(url)
            .build()

        return client.newCall(request).execute()
    }
}

// Usage example
fun main() {
    val networkClient = NetworkClient()

    // Communicate with a local IoT device
    val localResponse = networkClient.getFromLocalDevice("192.168.1.10")
    println(localResponse?.body?.string())

    // Communicate with the cloud API
    val cloudResponse = networkClient.getFromCloudApi("data")
    println(cloudResponse?.body?.string())
}